INSERT INTO products (slug, name, image_url, category_id, description_en, description_ar, composition_en, composition_ar, indication_en, indication_ar, dosage_en, dosage_ar, side_effects_en, side_effects_ar, contraindications_en, contraindications_ar, storage_en, storage_ar, packaging_en, packaging_ar, is_featured, display_order) VALUES
('amristar', 'AMRISTAR', 'https://shibapharma.com/media/758/07-Amrystar.jpg', (SELECT id FROM product_categories WHERE slug='analgesics'), 'Pain relief medication used for the treatment of mild to moderate pain and fever.', 'دواء مسكن للآلام يستخدم لعلاج الآلام الخفيفة إلى المتوسطة والحمى.', 'Each tablet contains Paracetamol 500mg and Caffeine 65mg', 'يحتوي كل قرص على باراسيتامول 500 ملجم وكافيين 65 ملجم', 'Headache, migraine, toothache, backache, muscular pain, rheumatic pain, dysmenorrhea, and fever.', 'الصداع، الصداع النصفي، ألم الأسنان، آلام الظهر، آلام العضلات، آلام الروماتيزم، عسر الطمث، والحمى.', 'Adults and children over 12 years: 1-2 tablets every 4-6 hours as needed. Do not exceed 8 tablets in 24 hours.', 'البالغون والأطفال فوق 12 سنة: 1-2 قرص كل 4-6 ساعات حسب الحاجة. لا تتجاوز 8 أقراص في 24 ساعة.', 'Rarely, allergic reactions may occur. Consult your doctor if symptoms persist.', 'نادراً ما قد تحدث تفاعلات حساسية. استشر طبيبك إذا استمرت الأعراض.', 'Hypersensitivity to any of the components. Severe hepatic impairment.', 'فرط الحساسية لأي من المكونات. القصور الكبدي الشديد.', 'Store below 30°C, in a dry place, protected from light.', 'يحفظ في درجة حرارة أقل من 30 درجة مئوية، في مكان جاف، بعيداً عن الضوء.', 'Box containing 2 blisters of 10 tablets each', 'علبة تحتوي على شريطين من 10 أقراص لكل منهما', true, 0),
('diclosan-fast', 'DICLOSAN FAST', 'https://shibapharma.com/media/1/conversions/IMG_20170614_150102-Medium-Image.jpg', (SELECT id FROM product_categories WHERE slug='analgesics'), 'Fast-acting non-steroidal anti-inflammatory drug for pain relief.', 'دواء مضاد للالتهابات غير ستيرويدي سريع المفعول لتخفيف الألم.', 'Each tablet contains Diclofenac Potassium 50mg', 'يحتوي كل قرص على ديكلوفيناك البوتاسيوم 50 ملجم', 'Acute pain, inflammatory conditions, rheumatoid arthritis, osteoarthritis.', 'الألم الحاد، الحالات الالتهابية، التهاب المفاصل الروماتويدي، هشاشة العظام.', 'Adults: 50-150mg daily in 2-3 divided doses.', 'البالغون: 50-150 ملجم يومياً مقسمة على 2-3 جرعات.', 'Gastrointestinal disturbances, headache, dizziness.', 'اضطرابات الجهاز الهضمي، صداع، دوخة.', 'History of GI bleeding, renal impairment, pregnancy in third trimester.', 'تاريخ نزيف الجهاز الهضمي، القصور الكلوي، الحمل في الثلث الأخير.', 'Store below 25°C, protected from moisture.', 'يحفظ في درجة حرارة أقل من 25 درجة مئوية، بعيداً عن الرطوبة.', 'Box containing 20 film-coated tablets', 'علبة تحتوي على 20 قرص مغلف', true, 1),
('fenirgic', 'FENIRGIC', 'https://shibapharma.com/media/2/conversions/fenirgic-Medium-Image.jpg', (SELECT id FROM product_categories WHERE slug='anti-histamine'), 'Antihistamine medication for allergic conditions.', 'دواء مضاد للهيستامين للحالات التحسسية. ', 'Each 5ml contains Chlorpheniramine Maleate 2mg', 'يحتوي كل 5 مل على كلورفينيرامين ماليات 2 ملجم', 'Allergic rhinitis, urticaria, hay fever, allergic skin reactions.', 'التهاب الأنف التحسسي، الشرى، حمى القش، تفاعلات الجلد التحسسية.', 'Adults: 4mg every 4-6 hours. Children 6-12 years: 2mg every 4-6 hours.', 'البالغون: 4 ملجم كل 4-6 ساعات. الأطفال 6-12 سنة: 2 ملجم كل 4-6 ساعات.', 'Drowsiness, dry mouth, blurred vision.', 'النعاس، جفاف الفم، عدم وضوح الرؤية.', 'Glaucoma, urinary retention, during MAO inhibitor therapy.', 'الجلوكوما، احتباس البول، خلال العلاج بمثبطات MAO.', 'Store below 30°C, protected from light.', 'يحفظ في درجة حرارة أقل من 30 درجة مئوية، بعيداً عن الضوء.', 'Bottle of 100ml syrup', 'زجاجة 100 مل شراب', true, 2),
('kipromax', 'KIPROMAX SYRUP & TAB', 'https://shibapharma.com/media/3/conversions/kipromax-Medium-Image.jpg', (SELECT id FROM product_categories WHERE slug='antibiotics'), 'Broad-spectrum antibiotic for bacterial infections.', 'مضاد حيوي واسع الطيف للعدوى البكتيرية.', 'Each tablet contains Ciprofloxacin 500mg', 'يحتوي كل قرص على سيبروفلوكساسين 500 ملجم', 'Urinary tract infections, respiratory infections, skin infections.', 'عدوى المسالك البولية، عدوى الجهاز التنفسي، عدوى الجلد.', 'Adults: 250-750mg twice daily depending on severity.', 'البالغون: 250-750 ملجم مرتين يومياً حسب الشدة.', 'Nausea, diarrhea, headache, dizziness.', 'غثيان، إسهال، صداع، دوخة.', 'Children, pregnancy, hypersensitivity to quinolones.', 'الأطفال، الحمل، فرط الحساسية للكينولونات.', 'Store below 30°C, in a dry place.', 'يحفظ في درجة حرارة أقل من 30 درجة مئوية، في مكان جاف.', 'Box containing 10 film-coated tablets', 'علبة تحتوي على 10 أقراص مغلفة', true, 3),
('lanprol', 'LANPROL', 'https://shibapharma.com/media/4/conversions/lanprol-Medium-Image.jpg', (SELECT id FROM product_categories WHERE slug='git'), 'Proton pump inhibitor for acid-related disorders.', 'مثبط مضخة البروتون للاضطرابات المتعلقة بالحموضة.', 'Each capsule contains Lansoprazole 30mg', 'تحتوي كل كبسولة على لانسوبرازول 30 ملجم', 'GERD, peptic ulcer, H. pylori eradication.', 'ارتجاع المريء، القرحة الهضمية، القضاء على جرثومة المعدة.', 'Adults: 15-30mg once daily before breakfast.', 'البالغون: 15-30 ملجم مرة واحدة يومياً قبل الإفطار.', 'Headache, diarrhea, abdominal pain.', 'صداع، إسهال، ألم في البطن.', 'Hypersensitivity to lansoprazole.', 'فرط الحساسية للانسوبرازول.', 'Store below 30°C, protected from moisture.', 'يحفظ في درجة حرارة أقل من 30 درجة مئوية، بعيداً عن الرطوبة.', 'Box containing 14 capsules', 'علبة تحتوي على 14 كبسولة', true, 4),
('shibafen', 'SHIBAFEN', 'https://shibapharma.com/media/838/conversions/images-Medium-Image.jpg', (SELECT id FROM product_categories WHERE slug='analgesics'), 'Anti-inflammatory and analgesic medication.', 'دواء مضاد للالتهابات ومسكن للآلام.', 'Each tablet contains Ibuprofen 400mg', 'يحتوي كل قرص على إيبوبروفين 400 ملجم', 'Pain, fever, inflammation, arthritis.', 'الألم، الحمى، الالتهاب، التهاب المفاصل.', 'Adults: 200-400mg every 4-6 hours. Max 1200mg daily.', 'البالغون: 200-400 ملجم كل 4-6 ساعات. الحد الأقصى 1200 ملجم يومياً.', 'Stomach upset, nausea, dizziness.', 'اضطراب المعدة، غثيان، دوخة.', 'GI bleeding, renal impairment, aspirin sensitivity.', 'نزيف الجهاز الهضمي، القصور الكلوي، حساسية الأسبرين.', 'Store below 25°C.', 'يحفظ في درجة حرارة أقل من 25 درجة مئوية.', 'Box containing 30 tablets', 'علبة تحتوي على 30 قرص', false, 5),
('amoxyshiba', 'AMOXYSHIBA', 'https://shibapharma.com/media/1/conversions/IMG_20170614_150102-Medium-Image.jpg', (SELECT id FROM product_categories WHERE slug='antibiotics'), 'Broad-spectrum penicillin antibiotic.', 'مضاد حيوي من البنسلين واسع الطيف.', 'Each capsule contains Amoxicillin 500mg', 'تحتوي كل كبسولة على أموكسيسيلين 500 ملجم', 'Respiratory infections, urinary infections, skin infections.', 'عدوى الجهاز التنفسي، عدوى المسالك البولية، عدوى الجلد.', 'Adults: 250-500mg every 8 hours.', 'البالغون: 250-500 ملجم كل 8 ساعات.', 'Diarrhea, nausea, rash.', 'إسهال، غثيان، طفح جلدي.', 'Penicillin allergy.', 'حساسية البنسلين.', 'Store below 25°C, in a dry place.', 'يحفظ في درجة حرارة أقل من 25 درجة مئوية، في مكان جاف.', 'Box containing 20 capsules', 'علبة تحتوي على 20 كبسولة', false, 6),
('cephashiba', 'CEPHASHIBA', 'https://shibapharma.com/media/3/conversions/kipromax-Medium-Image.jpg', (SELECT id FROM product_categories WHERE slug='antibiotics'), 'Cephalosporin antibiotic for bacterial infections.', 'مضاد حيوي من السيفالوسبورين للعدوى البكتيرية.', 'Each capsule contains Cephalexin 500mg', 'تحتوي كل كبسولة على سيفالكسين 500 ملجم', 'Skin infections, respiratory infections, bone infections.', 'عدوى الجلد، عدوى الجهاز التنفسي، عدوى العظام.', 'Adults: 250-500mg every 6 hours.', 'البالغون: 250-500 ملجم كل 6 ساعات.', 'Diarrhea, stomach upset, rash.', 'إسهال، اضطراب المعدة، طفح جلدي.', 'Cephalosporin allergy.', 'حساسية السيفالوسبورين.', 'Store below 25°C.', 'يحفظ في درجة حرارة أقل من 25 درجة مئوية.', 'Box containing 16 capsules', 'علبة تحتوي على 16 كبسولة', false, 7),
('azishiba', 'AZISHIBA', 'https://shibapharma.com/media/1/conversions/IMG_20170614_150102-Medium-Image.jpg', (SELECT id FROM product_categories WHERE slug='antibiotics'), 'Macrolide antibiotic for various infections.', 'مضاد حيوي من الماكروليد للعدوى المختلفة.', 'Each tablet contains Azithromycin 500mg', 'يحتوي كل قرص على أزيثروميسين 500 ملجم', 'Respiratory infections, STIs, skin infections.', 'عدوى الجهاز التنفسي، الأمراض المنقولة جنسياً، عدوى الجلد.', 'Adults: 500mg once daily for 3 days.', 'البالغون: 500 ملجم مرة واحدة يومياً لمدة 3 أيام.', 'Nausea, diarrhea, abdominal pain.', 'غثيان، إسهال، ألم في البطن.', 'Macrolide allergy, liver disease.', 'حساسية الماكروليد، أمراض الكبد.', 'Store below 30°C, protected from moisture.', 'يحفظ في درجة حرارة أقل من 30 درجة مئوية، بعيداً عن الرطوبة.', 'Box containing 3 tablets', 'علبة تحتوي على 3 أقراص', false, 8),
('shibaclav', 'SHIBACLAV', 'https://shibapharma.com/media/3/conversions/kipromax-Medium-Image.jpg', (SELECT id FROM product_categories WHERE slug='antibiotics'), 'Combined antibiotic for resistant bacteria.', 'مضاد حيوي مركب للبكتيريا المقاومة.', 'Each tablet contains Amoxicillin 875mg + Clavulanic Acid 125mg', 'يحتوي كل قرص على أموكسيسيلين 875 ملجم + حمض الكلافولانيك 125 ملجم', 'Sinusitis, otitis media, pneumonia, UTI.', 'التهاب الجيوب الأنفية، التهاب الأذن الوسطى، الالتهاب الرئوي، عدوى المسالك البولية.', 'Adults: 1 tablet every 12 hours.', 'البالغون: قرص واحد كل 12 ساعة.', 'Diarrhea, nausea, rash, vaginitis.', 'إسهال، غثيان، طفح جلدي، التهاب المهبل.', 'Penicillin allergy, history of hepatic dysfunction.', 'حساسية البنسلين، تاريخ خلل وظيفي كبدي.', 'Store below 25°C, protected from moisture.', 'يحفظ في درجة حرارة أقل من 25 درجة مئوية، بعيداً عن الرطوبة.', 'Box containing 14 tablets', 'علبة تحتوي على 14 قرص', false, 9),
('metshiba', 'METSHIBA', 'https://shibapharma.com/media/1/conversions/IMG_20170614_150102-Medium-Image.jpg', (SELECT id FROM product_categories WHERE slug='antibiotics'), 'Antiprotozoal and antibacterial agent.', 'عامل مضاد للأوالي ومضاد للبكتيريا.', 'Each tablet contains Metronidazole 500mg', 'يحتوي كل قرص على ميترونيدازول 500 ملجم', 'Amoebiasis, giardiasis, anaerobic bacterial infections.', 'داء الأميبا، داء الجيارديا، العدوى البكتيرية اللاهوائية.', 'Adults: 400-500mg every 8 hours.', 'البالغون: 400-500 ملجم كل 8 ساعات.', 'Metallic taste, nausea, headache.', 'طعم معدني، غثيان، صداع.', 'First trimester of pregnancy, alcohol consumption.', 'الثلث الأول من الحمل، استهلاك الكحول.', 'Store below 25°C, protected from light.', 'يحفظ في درجة حرارة أقل من 25 درجة مئوية، بعيداً عن الضوء.', 'Box containing 20 tablets', 'علبة تحتوي على 20 قرص', false, 10),
('omeshiba', 'OMESHIBA', 'https://shibapharma.com/media/4/conversions/lanprol-Medium-Image.jpg', (SELECT id FROM product_categories WHERE slug='git'), 'Proton pump inhibitor for gastric acid conditions.', 'مثبط مضخة البروتون لحالات حمض المعدة.', 'Each capsule contains Omeprazole 20mg', 'تحتوي كل كبسولة على أوميبرازول 20 ملجم', 'GERD, peptic ulcer, Zollinger-Ellison syndrome.', 'ارتجاع المريء، القرحة الهضمية، متلازمة زولينجر إليسون.', 'Adults: 20mg once daily.', 'البالغون: 20 ملجم مرة واحدة يومياً.', 'Headache, nausea, diarrhea.', 'صداع، غثيان، إسهال.', 'Hypersensitivity to proton pump inhibitors.', 'فرط الحساسية لمثبطات مضخة البروتون.', 'Store below 25°C, protected from moisture.', 'يحفظ في درجة حرارة أقل من 25 درجة مئوية، بعيداً عن الرطوبة.', 'Box containing 14 capsules', 'علبة تحتوي على 14 كبسولة', false, 11),
('raniplus', 'RANIPLUS', 'https://shibapharma.com/media/4/conversions/lanprol-Medium-Image.jpg', (SELECT id FROM product_categories WHERE slug='git'), 'H2 receptor antagonist for acid control.', 'مضاد مستقبلات H2 للتحكم في الحموضة.', 'Each tablet contains Ranitidine 150mg', 'يحتوي كل قرص على رانيتيدين 150 ملجم', 'Peptic ulcer, GERD, Zollinger-Ellison syndrome.', 'القرحة الهضمية، ارتجاع المريء، متلازمة زولينجر إليسون.', 'Adults: 150mg twice daily or 300mg at bedtime.', 'البالغون: 150 ملجم مرتين يومياً أو 300 ملجم عند النوم.', 'Headache, constipation, diarrhea.', 'صداع، إمساك، إسهال.', 'Hypersensitivity to ranitidine.', 'فرط الحساسية للرانيتيدين.', 'Store below 30°C.', 'يحفظ في درجة حرارة أقل من 30 درجة مئوية.', 'Box containing 20 tablets', 'علبة تحتوي على 20 قرص', false, 12),
('domshiba', 'DOMSHIBA', 'https://shibapharma.com/media/4/conversions/lanprol-Medium-Image.jpg', (SELECT id FROM product_categories WHERE slug='git'), 'Antiemetic and prokinetic agent.', 'عامل مضاد للقيء ومنشط للحركة.', 'Each tablet contains Domperidone 10mg', 'يحتوي كل قرص على دومبيريدون 10 ملجم', 'Nausea, vomiting, dyspepsia, gastroparesis.', 'غثيان، قيء، عسر الهضم، شلل المعدة.', 'Adults: 10mg three times daily before meals.', 'البالغون: 10 ملجم ثلاث مرات يومياً قبل الوجبات.', 'Dry mouth, headache, diarrhea.', 'جفاف الفم، صداع، إسهال.', 'GI bleeding, mechanical obstruction, prolactinoma.', 'نزيف الجهاز الهضمي، انسداد ميكانيكي، ورم البرولاكتين.', 'Store below 30°C.', 'يحفظ في درجة حرارة أقل من 30 درجة مئوية.', 'Box containing 30 tablets', 'علبة تحتوي على 30 قرص', false, 13),
('loperashiba', 'LOPERASHIBA', 'https://shibapharma.com/media/4/conversions/lanprol-Medium-Image.jpg', (SELECT id FROM product_categories WHERE slug='git'), 'Antidiarrheal medication.', 'دواء مضاد للإسهال.', 'Each capsule contains Loperamide 2mg', 'تحتوي كل كبسولة على لوبيراميد 2 ملجم', 'Acute and chronic diarrhea.', 'الإسهال الحاد والمزمن.', 'Adults: Initial 4mg then 2mg after each loose stool. Max 16mg daily.', 'البالغون: 4 ملجم في البداية ثم 2 ملجم بعد كل براز رخو. الحد الأقصى 16 ملجم يومياً.', 'Constipation, abdominal cramps, drowsiness.', 'إمساك، تقلصات بطنية، نعاس.', 'Bloody diarrhea, acute dysentery, children under 2 years.', 'إسهال دموي، زحار حاد، أطفال أقل من سنتين.', 'Store below 30°C.', 'يحفظ في درجة حرارة أقل من 30 درجة مئوية.', 'Box containing 20 capsules', 'علبة تحتوي على 20 كبسولة', false, 14),
('loratshiba', 'LORATSHIBA', 'https://shibapharma.com/media/2/conversions/fenirgic-Medium-Image.jpg', (SELECT id FROM product_categories WHERE slug='anti-histamine'), 'Non-sedating antihistamine for allergies.', 'مضاد هيستامين غير مسبب للنعاس للحساسية.', 'Each tablet contains Loratadine 10mg', 'يحتوي كل قرص على لوراتادين 10 ملجم', 'Allergic rhinitis, chronic urticaria.', 'التهاب الأنف التحسسي، الشرى المزمن.', 'Adults and children over 12: 10mg once daily.', 'البالغون والأطفال فوق 12 سنة: 10 ملجم مرة واحدة يومياً.', 'Headache, drowsiness (rare), dry mouth.', 'صداع، نعاس (نادر)، جفاف الفم.', 'Hypersensitivity to loratadine.', 'فرط الحساسية للوراتادين.', 'Store below 25°C.', 'يحفظ في درجة حرارة أقل من 25 درجة مئوية.', 'Box containing 20 tablets', 'علبة تحتوي على 20 قرص', false, 15),
('cetishiba', 'CETISHIBA', 'https://shibapharma.com/media/2/conversions/fenirgic-Medium-Image.jpg', (SELECT id FROM product_categories WHERE slug='anti-histamine'), 'Second-generation antihistamine.', 'مضاد هيستامين من الجيل الثاني.', 'Each tablet contains Cetirizine 10mg', 'يحتوي كل قرص على سيتيريزين 10 ملجم', 'Seasonal allergic rhinitis, perennial allergic rhinitis, chronic urticaria.', 'التهاب الأنف التحسسي الموسمي، التهاب الأنف التحسسي الدائم، الشرى المزمن.', 'Adults: 10mg once daily.', 'البالغون: 10 ملجم مرة واحدة يومياً.', 'Drowsiness, dry mouth, fatigue.', 'نعاس، جفاف الفم، إرهاق.', 'Severe renal impairment, hypersensitivity.', 'القصور الكلوي الشديد، فرط الحساسية.', 'Store below 25°C.', 'يحفظ في درجة حرارة أقل من 25 درجة مئوية.', 'Box containing 20 tablets', 'علبة تحتوي على 20 قرص', false, 16),
('amloshiba', 'AMLOSHIBA', 'https://shibapharma.com/media/838/conversions/images-Medium-Image.jpg', (SELECT id FROM product_categories WHERE slug='cardiovascular'), 'Calcium channel blocker for hypertension.', 'مانع قنوات الكالسيوم لارتفاع ضغط الدم.', 'Each tablet contains Amlodipine 5mg', 'يحتوي كل قرص على أملوديبين 5 ملجم', 'Hypertension, chronic stable angina, vasospastic angina.', 'ارتفاع ضغط الدم، الذبحة الصدرية المستقرة المزمنة، الذبحة التشنجية الوعائية.', 'Adults: 5-10mg once daily.', 'البالغون: 5-10 ملجم مرة واحدة يومياً.', 'Edema, headache, fatigue, dizziness.', 'وذمة، صداع، إرهاق، دوخة.', 'Severe hypotension, cardiogenic shock.', 'انخفاض ضغط الدم الشديد، صدمة قلبية.', 'Store below 30°C.', 'يحفظ في درجة حرارة أقل من 30 درجة مئوية.', 'Box containing 30 tablets', 'علبة تحتوي على 30 قرص', false, 17),
