('paraceshiba', 'PARACESHIBA', 'https://shibapharma.com/media/838/conversions/images-Medium-Image.jpg', (SELECT id FROM product_categories WHERE slug='analgesics'), 'Analgesic and antipyretic.', 'مسكن للآلام وخافض للحرارة.', 'Each tablet contains Paracetamol 500mg', 'يحتوي كل قرص على باراسيتامول 500 ملجم', 'Pain, fever, headache, cold symptoms.', 'الألم، الحمى، الصداع، أعراض البرد.', 'Adults: 500-1000mg every 4-6 hours. Max 4g daily.', 'البالغون: 500-1000 ملجم كل 4-6 ساعات. الحد الأقصى 4 غرام يومياً.', 'Rare allergic reactions.', 'تفاعلات حساسية نادرة.', 'Severe hepatic impairment, hypersensitivity.', 'القصور الكبدي الشديد، فرط الحساسية.', 'Store below 25°C.', 'يحفظ في درجة حرارة أقل من 25 درجة مئوية.', 'Box containing 24 tablets', 'علبة تحتوي على 24 قرص', false, 40),
('meloxishiba', 'MELOXISHIBA', 'https://shibapharma.com/media/838/conversions/images-Medium-Image.jpg', (SELECT id FROM product_categories WHERE slug='analgesics'), 'NSAID for pain and inflammation.', 'مضاد التهاب غير ستيرويدي للألم والالتهاب.', 'Each tablet contains Meloxicam 15mg', 'يحتوي كل قرص على ميلوكسيكام 15 ملجم', 'Osteoarthritis, rheumatoid arthritis.', 'هشاشة العظام، التهاب المفاصل الروماتويدي.', 'Adults: 7.5-15mg once daily.', 'البالغون: 7.5-15 ملجم مرة واحدة يومياً.', 'GI upset, headache, edema.', 'اضطراب الجهاز الهضمي، صداع، وذمة.', 'Active GI bleeding, severe renal impairment.', 'نزيف الجهاز الهضمي النشط، القصور الكلوي الشديد.', 'Store below 25°C.', 'يحفظ في درجة حرارة أقل من 25 درجة مئوية.', 'Box containing 20 tablets', 'علبة تحتوي على 20 قرص', false, 41),
('tramashiba', 'TRAMASHIBA', 'https://shibapharma.com/media/838/conversions/images-Medium-Image.jpg', (SELECT id FROM product_categories WHERE slug='analgesics'), 'Opioid analgesic for moderate to severe pain.', 'مسكن أفيوني للألم المتوسط إلى الشديد.', 'Each capsule contains Tramadol 50mg', 'تحتوي كل كبسولة على ترامادول 50 ملجم', 'Moderate to severe pain.', 'الألم المتوسط إلى الشديد.', 'Adults: 50-100mg every 4-6 hours. Max 400mg daily.', 'البالغون: 50-100 ملجم كل 4-6 ساعات. الحد الأقصى 400 ملجم يومياً.', 'Nausea, dizziness, constipation, drowsiness.', 'غثيان، دوخة، إمساك، نعاس.', 'Acute intoxication, epilepsy, MAO inhibitors.', 'التسمم الحاد، الصرع، مثبطات MAO.', 'Store below 25°C.', 'يحفظ في درجة حرارة أقل من 25 درجة مئوية.', 'Box containing 20 capsules', 'علبة تحتوي على 20 كبسولة', false, 42),
('orphenshiba', 'ORPHENSHIBA', 'https://shibapharma.com/media/3/conversions/kipromax-Medium-Image.jpg', (SELECT id FROM product_categories WHERE slug='cns'), 'Muscle relaxant for spasms.', 'مرخي عضلات للتشنجات.', 'Each tablet contains Orphenadrine 100mg', 'يحتوي كل قرص على أورفينادرين 100 ملجم', 'Muscle spasm, Parkinsonism.', 'تشنج العضلات، داء باركنسون.', 'Adults: 100mg twice daily.', 'البالغون: 100 ملجم مرتين يومياً.', 'Dry mouth, drowsiness, dizziness.', 'جفاف الفم، نعاس، دوخة.', 'Glaucoma, myasthenia gravis, urinary retention.', 'الجلوكوما، الوهن العضلي الوبيل، احتباس البول.', 'Store below 25°C.', 'يحفظ في درجة حرارة أقل من 25 درجة مئوية.', 'Box containing 20 tablets', 'علبة تحتوي على 20 قرص', false, 43),
('gabashiba', 'GABASHIBA', 'https://shibapharma.com/media/3/conversions/kipromax-Medium-Image.jpg', (SELECT id FROM product_categories WHERE slug='cns'), 'Anticonvulsant and neuropathic pain medication.', 'مضاد اختلاج ودواء لآلام الأعصاب.', 'Each capsule contains Gabapentin 300mg', 'تحتوي كل كبسولة على غابابنتين 300 ملجم', 'Epilepsy, neuropathic pain, postherpetic neuralgia.', 'الصرع، ألم الأعصاب، الألم العصبي التالي للهربس.', 'Adults: 300-1200mg three times daily.', 'البالغون: 300-1200 ملجم ثلاث مرات يومياً.', 'Drowsiness, dizziness, ataxia.', 'نعاس، دوخة، ترنح.', 'Hypersensitivity to gabapentin.', 'فرط الحساسية للغابابنتين.', 'Store below 25°C.', 'يحفظ في درجة حرارة أقل من 25 درجة مئوية.', 'Box containing 30 capsules', 'علبة تحتوي على 30 كبسولة', false, 44),
('carbamazeshiba', 'CARBAMAZESHIBA', 'https://shibapharma.com/media/3/conversions/kipromax-Medium-Image.jpg', (SELECT id FROM product_categories WHERE slug='cns'), 'Anticonvulsant for epilepsy and bipolar disorder.', 'مضاد اختلاج للصرع واضطراب ثنائي القطب.', 'Each tablet contains Carbamazepine 200mg', 'يحتوي كل قرص على كاربامازيبين 200 ملجم', 'Epilepsy, trigeminal neuralgia, bipolar disorder.', 'الصرع، ألم العصب الثلاثي التوائم، اضطراب ثنائي القطب.', 'Adults: 100-400mg twice daily.', 'البالغون: 100-400 ملجم مرتين يومياً.', 'Dizziness, drowsiness, ataxia, nausea.', 'دوخة، نعاس، ترنح، غثيان.', 'Bone marrow depression, MAO inhibitors, porphyria.', 'تثبيط نخاع العظم، مثبطات MAO، البورفيريا.', 'Store below 25°C.', 'يحفظ في درجة حرارة أقل من 25 درجة مئوية.', 'Box containing 50 tablets', 'علبة تحتوي على 50 قرص', false, 45),
('zincshiba', 'ZINCSHIBA', 'https://shibapharma.com/media/838/conversions/images-Medium-Image.jpg', (SELECT id FROM product_categories WHERE slug='vitamins'), 'Zinc supplement for immune support.', 'مكمل الزنك لدعم المناعة.', 'Each tablet contains Zinc Sulfate 220mg (50mg elemental zinc)', 'يحتوي كل قرص على كبريتات الزنك 220 ملجم (50 ملجم زنك عنصري)', 'Zinc deficiency, wound healing, immune support.', 'نقص الزنك، شفاء الجروح، دعم المناعة.', 'Adults: 1 tablet daily with food.', 'البالغون: قرص واحد يومياً مع الطعام.', 'Nausea, metallic taste.', 'غثيان، طعم معدني.', 'Copper deficiency (at high doses).', 'نقص النحاس (بالجرعات العالية).', 'Store below 25°C.', 'يحفظ في درجة حرارة أقل من 25 درجة مئوية.', 'Bottle of 30 tablets', 'زجاجة 30 قرص', false, 46),
('omega3shiba', 'OMEGA-3 SHIBA', 'https://shibapharma.com/media/838/conversions/images-Medium-Image.jpg', (SELECT id FROM product_categories WHERE slug='vitamins'), 'Fish oil supplement for cardiovascular health.', 'مكمل زيت السمك لصحة القلب والأوعية الدموية.', 'Each capsule contains Fish Oil 1000mg (EPA 180mg, DHA 120mg)', 'تحتوي كل كبسولة على زيت السمك 1000 ملجم (EPA 180 ملجم، DHA 120 ملجم)', 'Cardiovascular health, triglyceride reduction, brain health.', 'صحة القلب والأوعية الدموية، خفض الدهون الثلاثية، صحة الدماغ.', 'Adults: 1-3 capsules daily with meals.', 'البالغون: 1-3 كبسولات يومياً مع الوجبات.', 'Fishy aftertaste, GI upset.', 'طعم سمكي، اضطراب الجهاز الهضمي.', 'Fish allergy.', 'حساسية السمك.', 'Store below 25°C, protected from light.', 'يحفظ في درجة حرارة أقل من 25 درجة مئوية، بعيداً عن الضوء.', 'Bottle of 60 soft capsules', 'زجاجة 60 كبسولة لينة', false, 47),
('multivitshiba', 'MULTIVIT SHIBA', 'https://shibapharma.com/media/838/conversions/images-Medium-Image.jpg', (SELECT id FROM product_categories WHERE slug='vitamins'), 'Complete multivitamin and mineral supplement.', 'مكمل متعدد الفيتامينات والمعادن الشامل.', 'Contains 23 essential vitamins and minerals', 'يحتوي على 23 فيتامين ومعدن أساسي', 'Nutritional supplementation, vitamin deficiencies.', 'المكملات الغذائية، نقص الفيتامينات.', 'Adults: 1 tablet daily with food.', 'البالغون: قرص واحد يومياً مع الطعام.', 'Rarely, GI upset.', 'نادراً، اضطراب الجهاز الهضمي.', 'Hypervitaminosis, iron overload disorders.', 'فرط الفيتامينات، اضطرابات فرط الحديد.', 'Store below 25°C, protected from light.', 'يحفظ في درجة حرارة أقل من 25 درجة مئوية، بعيداً عن الضوء.', 'Bottle of 30 tablets', 'زجاجة 30 قرص', false, 48);INSERT INTO news_articles (slug, title_en, title_ar, excerpt_en, excerpt_ar, image_url, published_date, display_order) VALUES
('news-1', 'Shiba Pharma Honored as One of Yemen''s Most Prominent Companies for 2025', 'تكريم سبأ فارما كأحد أبرز الشركات اليمنية لعام 2025', 'The Investor Foundation for Economic Journalism honored Shiba Pharma as one of the most prominent companies in Yemen for 2025, in recognition of its excellence in producing pharmaceuticals.', 'كرّمت مؤسسة المستثمر للصحافة الاقتصادية سبأ فارما كإحدى أبرز الشركات في اليمن لعام 2025، تقديراً لتميزها في إنتاج الأدوية.', 'https://shibapharma.com/media/850/conversions/shiba-pharma-top-company-yemen-2025-Medium-Image.jpg', '2025-09-09'::date, 0),
('news-2', 'Dr. Muhammad Al-Madani - Chairman of the High Authority for Medicines praises the role', 'د. محمد المدني - رئيس الهيئة العليا للأدوية يشيد بالدور', 'Dr. Muhammad Al-Madani, Chairman of the High Authority for Medicines, praised the important role of Shiba Pharma in developing the pharmaceutical industry.', 'أشاد د. محمد المدني، رئيس الهيئة العليا للأدوية، بالدور المهم لسبأ فارما في تطوير الصناعة الدوائية.', 'https://shibapharma.com/media/288/conversions/Untitled3-Medium-Image.jpg', '2022-09-28'::date, 1),
('news-3', 'A pleasant visit to the Doctors Without Borders team at the Shiba Pharma factory 17th', 'زيارة ودية لفريق أطباء بلا حدود لمصنع سبأ فارما', 'The Doctors Without Borders team visited Shiba Pharma factory on 17th November to learn about the manufacturing processes and quality standards.', 'زار فريق أطباء بلا حدود مصنع سبأ فارما في 17 نوفمبر للتعرف على عمليات التصنيع ومعايير الجودة.', 'https://shibapharma.com/media/287/conversions/Untitled5-Medium-Image.jpg', '2022-09-28'::date, 2),
('news-4', 'Dr. Hazem Al-Rabahi receives a number of health ministers from various countries', 'د. حازم الرباحي يستقبل عدداً من وزراء الصحة من مختلف الدول', 'Dr. Hazem Al-Rabahi received health ministers from various countries to discuss pharmaceutical cooperation.', 'استقبل د. حازم الرباحي وزراء صحة من مختلف الدول لمناقشة التعاون الدوائي.', 'https://shibapharma.com/media/286/conversions/Untitled1-Medium-Image.jpg', '2022-09-28'::date, 3);
INSERT INTO videos (title_en, title_ar, description_en, description_ar, thumbnail_url, video_url, published_date, display_order) VALUES
('Certificates and Awards', 'الشهادات والجوائز', 'The company produces more than 300+ pharmaceutical products in various dosage forms (syrups, suspensions, tablets, capsules, and others). Shiba Pharma obtained the WHO-GMP certification from the World Health Organization in 1999, becoming the first Yemeni pharmaceutical company to receive this certification.', 'تنتج الشركة أكثر من 300 منتج دوائي بأشكال صيدلانية متنوعة (شراب، معلقات، أقراص، كبسولات، وغيرها). حصلت سبأ فارما على شهادة WHO-GMP من منظمة الصحة العالمية عام 1999، لتصبح أول شركة أدوية يمنية تحصل على هذه الشهادة.', 'https://shibapharma.com/media/289/conversions/video-thumb-1-Medium-Image.jpg', '#', '2020-01-31'::date, 0),
('Shiba Pharma', 'سبأ فارما', 'Shiba Pharma Company produces and develops pharmaceuticals for human use in various forms and medical uses with the latest and best scientific methods used to ensure its quality and competitive prices. The company launched its first production of medicines that conform to the latest international standards which Established in the pharmacopoeias in the year 1997 AD.', 'شركة سبأ فارما تنتج وتطور الأدوية للاستخدام البشري بأشكال ومستخدمات طبية متنوعة باستخدام أحدث وأفضل الأساليب العلمية لضمان الجودة والأسعار التنافسية. أطلقت الشركة أول إنتاج للأدوية التي تتوافق مع أحدث المعايير الدولية المنصوص عليها في دساتير الأدوية عام 1997م.', 'https://shibapharma.com/media/290/conversions/video-thumb-2-Medium-Image.jpg', '#', '2020-01-31'::date, 1);
